use soroban_sdk::{contract, contractimpl, Address, Env, Bytes, Symbol, Vec, Val};

#[contractimpl]
impl BridgeContract {
    // UNSAFE: invoke_contract without validation
    pub fn transfer(env: Env, target: Address, amount: i128) {
        let client = Client::new(&env, &target);
        client.transfer(&amount);
    }

    // UNSAFE: direct env.invoke_contract without result check
    pub fn relay(env: Env, contract: Address, func: Bytes, args: Bytes) {
        env.invoke_contract(&contract, &func, &args);
    }

    // UNSAFE: call_contract without validation
    pub fn call_external(env: Env, target: Address, method: Symbol, args: Vec<Val>) {
        env.invoke_contract(&target, &method, &args);
    }

    // NO INVOCATION (not flagged)
    pub fn get_balance(env: Env, address: Address) -> i128 {
        env.storage().instance().get(&address).unwrap_or(0)
    }
}
